import { useState } from "react";
import axios from "axios";

const Event_booking = () => {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [event_date, setEvent_date] = useState("");
  const [event_type, setEvent_type] = useState("");
  const [guests, setGuests] = useState("");

  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState("");
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");
    setSuccess("");

    try {
      const formdata = new FormData();
      formdata.append("name", name);
      formdata.append("email", email);
      formdata.append("phone", phone);
      formdata.append("event_date", event_date);
      formdata.append("event_type", event_type);
      formdata.append("guests", guests);

      const response = await axios.post(
        "https://calebtonny.alwaysdata.net/api/event-booking",
        formdata
      );

      setLoading(false);
      setSuccess(response.data.message);

      // reset fields
      setName("");
      setEmail("");
      setPhone("");
      setEvent_date("");
      setEvent_type("");
      setGuests("");

    } catch (err) {
      setLoading(false);
      setError("Failed to send booking request");
      console.error(err);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        name="name"
        placeholder="Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
        required
      />

      <input
        name="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        required
      />

      <input
        name="phone"
        placeholder="Phone"
        value={phone}
        onChange={(e) => setPhone(e.target.value)}
        required
      />

      <input
        type="date"
        name="event_date"
        value={event_date}
        onChange={(e) => setEvent_date(e.target.value)}
        required
      />

      <input
        name="event_type"
        placeholder="Event Type"
        value={event_type}
        onChange={(e) => setEvent_type(e.target.value)}
        required
      />

      <input
        type="number"
        name="guests"
        placeholder="Guests"
        value={guests}
        onChange={(e) => setGuests(e.target.value)}
        required
      />

      <button type="submit">
        {loading ? "Sending..." : "Send Event Request"}
      </button>

      {success && <p style={{ color: "green" }}>{success}</p>}
      {error && <p style={{ color: "red" }}>{error}</p>}
    </form>
  );
};

export default Event_booking;
